export function searchItems(query: string): BagdropItem[] {
  if (!query.trim()) return BAGDROP_ITEMS.slice(0, 30)
  const q = query.toLowerCase()
  return BAGDROP_ITEMS.filter(
    i => i.name.toLowerCase().includes(q) || i.description.toLowerCase().includes(q)
  ).slice(0, 50)
}
